                    // For example, if item is a com.huawei.digitalpayment.customer.httplib.response.ODDisplayItemResp:
                    // var itemAmount = item.getAmount();
                    // var itemName = item.getName();
                    // console.log(`  - Item ${index}: ${itemName}, Amount: ${itemAmount}`);

                    // Example: Modify an item's amount (hypothetical method name)
                    // if (item.getName().includes("Expensive Item")) {
                    //     console.log("  [Frida] Modifying 'Expensive Item' amount from " + item.getAmount() + " to 1.00");
                    //     item.setAmount(Java.use('java.math.BigDecimal').$new("1.00")); // Assuming BigDecimal
                    // }
                    console.log("  [Frida] Item " + index + ": " + item.toString()); // Generic toString for inspection
                });

                // Re-call the original method with potentially modified 'obj'
                this.convert(baseViewHolder, obj);
            } else {
                console.log("[Frida] Unexpected object type in convert: " + obj.$className);
                this.convert(baseViewHolder, obj);
